import random
import time

class Lift:
    def __init__(self, lift_id, num_floors):
        self.lift_id = lift_id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.num_floors = num_floors
        self.is_moving = False

    def add_destination(self, floor):
        if floor not in self.destination_floors:
            self.destination_floors.append(floor)
            self.destination_floors.sort(key=lambda x: (x - self.current_floor, abs(x - self.current_floor)))
            if len(self.destination_floors) == 1:
                if floor > self.current_floor:
                    self.direction = 1
                elif floor < self.current_floor:
                    self.direction = -1
                else:
                    self.direction = 0

    def move(self):
        if not self.destination_floors:
            self.direction = 0
            self.is_moving = False
            return

        self.is_moving = True

        if self.direction == 1:
            next_floor = self.current_floor + 1
            if next_floor > self.num_floors:
                self.direction = -1
                next_floor = self.current_floor - 1
        elif self.direction == -1:
            next_floor = self.current_floor - 1
            if next_floor < 1:
                self.direction = 1
                next_floor = self.current_floor + 1
        else:
            next_floor = self.current_floor

        if self.direction != 0:
            self.current_floor = next_floor
            print(f"Lift {self.lift_id} moving to floor {self.current_floor}")
            time.sleep(0.5)

        if self.current_floor in self.destination_floors:
            self.destination_floors.remove(self.current_floor)
            print(f"Lift {self.lift_id} arrived at floor {self.current_floor}")
            time.sleep(1)

            if not self.destination_floors:
                self.direction = 0
                self.is_moving = False
            else:
                next_destination = self.destination_floors[0]
                if next_destination > self.current_floor:
                    self.direction = 1
                elif next_destination < self.current_floor:
                    self.direction = -1
                else:
                    self.direction = 0

    def __str__(self):
        return f"Lift {self.lift_id}: Floor {self.current_floor}, Direction {self.direction}, Destinations {self.destination_floors}"


class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i + 1, num_floors) for i in range(num_lifts)]

    def call_lift(self, from_floor, to_floor):
        available_lifts = [lift for lift in self.lifts if not lift.is_moving]
        if available_lifts:
            closest_lift = min(available_lifts, key=lambda lift: abs(lift.current_floor - from_floor))
        else:
            closest_lift = min(self.lifts, key=lambda lift: abs(lift.current_floor - from_floor))

        print(f"Calling lift from floor {from_floor} to {to_floor}")
        closest_lift.add_destination(from_floor)
        closest_lift.add_destination(to_floor)

    def simulate_step(self):
        for lift in self.lifts:
            lift.move()

    def display_state(self):
        for lift in self.lifts:
            print(lift)


def simulate_building(num_floors, num_lifts, crowd_size, duration):
    building = Building(num_floors, num_lifts)

    for hour in range(duration):
        print(f"\n--- Hour {hour} ---")

        # Simulate different crowd sizes based on the time of day
        if 7 <= hour < 9:  # Morning rush
            requests_per_hour = crowd_size * 2
        elif 12 <= hour < 14:  # Lunch rush
            requests_per_hour = crowd_size * 1.5
        elif 17 <= hour < 19:  # Evening rush
            requests_per_hour = crowd_size * 2.5
        elif 22 <= hour or hour < 6: #Night
            requests_per_hour = crowd_size * 0.1
        else:  # Regular office hours
            requests_per_hour = crowd_size * 0.5

        for _ in range(int(requests_per_hour)):
            from_floor = random.randint(1, num_floors)
            to_floor = random.randint(1, num_floors)
            while from_floor == to_floor:
                to_floor = random.randint(1, num_floors)
            building.call_lift(from_floor, to_floor)

        # Simulate lift movement for the hour
        for _ in range(5):  # Simulate multiple steps per hour
            building.simulate_step()
            building.display_state()
            time.sleep(1)


if __name__ == "__main__":
    num_floors = 10
    num_lifts = 3
    crowd_size = 10
    simulation_duration = 24  # Hours

    simulate_building(num_floors, num_lifts, crowd_size, simulation_duration)

