import random
import time

class Elevator:
    def __init__(self, elevator_id, num_floors):
        self.elevator_id = elevator_id
        self.num_floors = num_floors
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.is_busy = False

    def __repr__(self):
        return f"Elevator {self.elevator_id}: Floor {self.current_floor}, Direction {self.direction}, Destinations {self.destination_floors}, Busy: {self.is_busy}"

    def add_destination(self, floor):
        if floor not in self.destination_floors:
            self.destination_floors.append(floor)
            self.destination_floors.sort(reverse=(self.direction == -1))
            self.is_busy = True

    def move(self):
        if not self.destination_floors:
            self.direction = 0
            self.is_busy = False
            return

        if self.direction == 0:
            next_destination = self.destination_floors[0]
            if next_destination > self.current_floor:
                self.direction = 1
            elif next_destination < self.current_floor:
                self.direction = -1
            else:
                self.destination_floors.pop(0)
                return

        if self.direction == 1:
            self.current_floor += 1
        elif self.direction == -1:
            self.current_floor -= 1

        if self.current_floor in self.destination_floors:
            self.destination_floors.remove(self.current_floor)
            print(f"Elevator {self.elevator_id} stopped at floor {self.current_floor}")
            time.sleep(0.5) # Simulate door opening/closing

        if self.current_floor == self.num_floors:
            self.direction = -1
        elif self.current_floor == 1:
            self.direction = 1

class Skyscraper:
    def __init__(self, num_floors, num_elevators):
        self.num_floors = num_floors
        self.elevators = [Elevator(i + 1, num_floors) for i in range(num_elevators)]

    def request_elevator(self, start_floor, destination_floor):
        available_elevators = [e for e in self.elevators if not e.is_busy]
        if available_elevators:
            elevator = min(available_elevators, key=lambda e: abs(e.current_floor - start_floor))
        else:
            elevator = min(self.elevators, key=lambda e: len(e.destination_floors)) # Choose least busy

        print(f"Request: Floor {start_floor} to {destination_floor}. Assigned Elevator {elevator.elevator_id}")
        elevator.add_destination(start_floor)
        elevator.add_destination(destination_floor)

    def run_simulation(self, duration, crowd_size):
        start_time = time.time()
        while time.time() - start_time < duration:
            # Simulate time-dependent crowd behavior
            current_time = time.localtime().tm_hour
            if 7 <= current_time < 9:  # Morning rush
                request_probability = 0.7 * crowd_size / 100
            elif 12 <= current_time < 13:  # Lunch rush
                request_probability = 0.4 * crowd_size / 100
            elif 17 <= current_time < 19:  # Evening rush
                request_probability = 0.8 * crowd_size / 100
            elif 22 <= current_time or current_time < 6: # Night
                request_probability = 0.01 * crowd_size / 100
            else:  # Daytime
                request_probability = 0.1 * crowd_size / 100

            if random.random() < request_probability:
                start_floor = random.randint(1, self.num_floors)
                destination_floor = random.randint(1, self.num_floors)
                while destination_floor == start_floor:
                    destination_floor = random.randint(1, self.num_floors)
                self.request_elevator(start_floor, destination_floor)

            for elevator in self.elevators:
                elevator.move()

            # Print elevator status
            for elevator in self.elevators:
                print(elevator)
            print("-" * 20)
            time.sleep(0.2)

if __name__ == "__main__":
    num_floors = 10
    num_elevators = 3
    simulation_duration = 60  # seconds
    crowd_size = 50 # Simulate 50 people in the building

    skyscraper = Skyscraper(num_floors, num_elevators)
    skyscraper.run_simulation(simulation_duration, crowd_size)

import random
import time

class Elevator:
    def __init__(self, elevator_id, num_floors):
        self.elevator_id = elevator_id
        self.num_floors = num_floors
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.passengers = []  # List of (destination_floor, entry_time)
        self.requests = [] # List of (floor, direction)

    def __repr__(self):
        return f"Elevator {self.elevator_id}: Floor {self.current_floor}, Direction {self.direction}, Passengers {len(self.passengers)}, Requests {len(self.requests)}"

    def add_request(self, floor, direction):
        if (floor, direction) not in self.requests:
            self.requests.append((floor, direction))
            self.requests.sort(key=lambda x: abs(x[0] - self.current_floor)) # Sort by distance

    def move(self):
        if self.direction == 1:
            if self.current_floor < self.num_floors:
                self.current_floor += 1
            else:
                self.direction = -1
                self.current_floor -= 1
        elif self.direction == -1:
            if self.current_floor > 1:
                self.current_floor -= 1
            else:
                self.direction = 1
                self.current_floor += 1
        else: # Idle
            if self.requests:
                next_floor, _ = self.requests[0]
                if next_floor > self.current_floor:
                    self.direction = 1
                    self.current_floor += 1
                elif next_floor < self.current_floor:
                    self.direction = -1
                    self.current_floor -= 1
                else:
                    pass # Already at the requested floor

    def operate(self, current_time):
        # Pick up passengers
        served_request = None
        for floor, direction in self.requests:
            if floor == self.current_floor:
                served_request = (floor, direction)
                break

        if served_request:
            self.requests.remove(served_request)

        # Drop off passengers
        dropped_off = []
        for destination_floor, entry_time in self.passengers:
            if destination_floor == self.current_floor:
                dropped_off.append((destination_floor, entry_time))

        for passenger in dropped_off:
            self.passengers.remove(passenger)

        # Change direction if necessary
        if not self.passengers and not self.requests:
            self.direction = 0
        elif not self.requests and self.direction == 0:
            self.direction = 1 # Default to going up if idle and no requests

class Building:
    def __init__(self, num_floors, num_elevators):
        self.num_floors = num_floors
        self.elevators = [Elevator(i + 1, num_floors) for i in range(num_elevators)]
        self.waiting_passengers = {} # {floor: [(destination_floor, time_requested)]}

    def __repr__(self):
        return f"Building: {self.num_floors} floors, {len(self.elevators)} elevators"

    def call_elevator(self, floor, destination_floor, current_time):
        # Find the closest elevator going in the right direction or idle
        best_elevator = None
        min_distance = float('inf')

        for elevator in self.elevators:
            if elevator.direction == 1 and elevator.current_floor <= floor or \
               elevator.direction == -1 and elevator.current_floor >= floor or \
               elevator.direction == 0:

                distance = abs(elevator.current_floor - floor)
                if distance < min_distance:
                    min_distance = distance
                    best_elevator = elevator

        if best_elevator:
            direction = 1 if destination_floor > floor else -1
            best_elevator.add_request(floor, direction)
            self.waiting_passengers.setdefault(floor, []).append((destination_floor, current_time))
            return best_elevator.elevator_id
        else:
            return None

    def update(self, current_time):
        for elevator in self.elevators:
            elevator.operate(current_time)
            elevator.move()

            # Pick up waiting passengers
            if elevator.current_floor in self.waiting_passengers:
                pickup_list = []
                for destination_floor, time_requested in self.waiting_passengers[elevator.current_floor]:
                    direction = 1 if destination_floor > elevator.current_floor else -1
                    if (elevator.direction == 1 and direction == 1) or \
                       (elevator.direction == -1 and direction == -1) or \
                       (elevator.direction == 0):
                        elevator.passengers.append((destination_floor, time_requested))
                        pickup_list.append((destination_floor, time_requested))
                        elevator.add_request(destination_floor, 0) # Add destination as a request

                for passenger in pickup_list:
                    self.waiting_passengers[elevator.current_floor].remove(passenger)
                if not self.waiting_passengers[elevator.current_floor]:
                    del self.waiting_passengers[elevator.current_floor]

def simulate_elevator_system(num_floors, num_elevators, crowd_size, simulation_duration):
    building = Building(num_floors, num_elevators)
    print(building)

    for current_time in range(simulation_duration):
        # Generate passenger requests based on time of day
        if 6 <= (current_time % 24) < 9:  # Morning rush
            request_probability = 0.7 * crowd_size / 100
        elif 11 <= (current_time % 24) < 14:  # Lunch rush
            request_probability = 0.4 * crowd_size / 100
        elif 16 <= (current_time % 24) < 19:  # Evening rush
            request_probability = 0.8 * crowd_size / 100
        elif 22 <= (current_time % 24) or (current_time % 24) < 2: # Night
            request_probability = 0.05 * crowd_size / 100
        else:  # Daytime
            request_probability = 0.1 * crowd_size / 100

        for floor in range(1, num_floors + 1):
            if random.random() < request_probability:
                destination_floor = random.randint(1, num_floors)
                while destination_floor == floor:
                    destination_floor = random.randint(1, num_floors)
                elevator_id = building.call_elevator(floor, destination_floor, current_time)
                if elevator_id:
                    print(f"Time {current_time}: Passenger requesting from floor {floor} to {destination_floor}. Elevator {elevator_id} dispatched.")
                else:
                    print(f"Time {current_time}: Passenger requesting from floor {floor} to {destination_floor}. No elevator available.")

        building.update(current_time)

        # Print elevator status
        if current_time % 5 == 0:
            print(f"--- Time {current_time} ---")
            for elevator in building.elevators:
                print(elevator)
            print(f"Waiting passengers: {building.waiting_passengers}")

        time.sleep(0.1) # Simulate time passing

if __name__ == "__main__":
    num_floors = 10
    num_elevators = 3
    crowd_size = 50
    simulation_duration = 100

    simulate_elevator_system(num_floors, num_elevators, crowd_size, simulation_duration)

