    def request_elevator(self, start_floor, destination_floor):
        available_elevators = [e for e in self.elevators if not e.is_busy]
        if available_elevators:
            elevator = min(available_elevators, key=lambda e: abs(e.current_floor - start_floor))
        else:
            elevator = min(self.elevators, key=lambda e: len(e.destination_floors)) # Choose least busy

        print(f"Request: Floor {start_floor} to {destination_floor}. Assigned Elevator {elevator.elevator_id}")
