import random
import time

class Elevator:
    def __init__(self, elevator_id, num_floors):
        self.elevator_id = elevator_id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.num_floors = num_floors
        self.is_moving = False

    def add_destination(self, floor):
        if 1 <= floor <= self.num_floors:
            if floor not in self.destination_floors:
                self.destination_floors.append(floor)
                self.destination_floors.sort(key=lambda x: (x - self.current_floor, abs(x - self.current_floor)))
                if self.direction == 0:
                    if floor > self.current_floor:
                        self.direction = 1
                    elif floor < self.current_floor:
                        self.direction = -1

    def move(self):
        if self.destination_floors:
            self.is_moving = True
            next_floor = self.destination_floors[0]
            if self.current_floor < next_floor:
                self.current_floor += 1
                self.direction = 1
            elif self.current_floor > next_floor:
                self.current_floor -= 1
                self.direction = -1
            else:
                self.destination_floors.pop(0)
                self.is_moving = False
                if self.destination_floors:
                    next_floor = self.destination_floors[0]
                    if next_floor > self.current_floor:
                        self.direction = 1
                    elif next_floor < self.current_floor:
                        self.direction = -1
                else:
                    self.direction = 0
        else:
            self.direction = 0
            self.is_moving = False

    def __str__(self):
        return f"Elevator {self.elevator_id}: Floor {self.current_floor}, Direction: {self.direction}, Destinations: {self.destination_floors}, Moving: {self.is_moving}"


class Skyscraper:
    def __init__(self, num_floors, num_elevators):
        self.num_floors = num_floors
        self.elevators = [Elevator(i + 1, num_floors) for i in range(num_elevators)]
        self.waiting_people = {}  # {floor: number of people}
        for i in range(1, num_floors + 1):
            self.waiting_people[i] = 0

    def call_elevator(self, floor, destination_floor):
        if 1 <= floor <= self.num_floors and 1 <= destination_floor <= self.num_floors and floor != destination_floor:
            self.waiting_people[floor] += 1
            available_elevators = [e for e in self.elevators if not e.is_moving]
            if available_elevators:
                closest_elevator = min(available_elevators, key=lambda e: abs(e.current_floor - floor))
                closest_elevator.add_destination(floor)
                closest_elevator.add_destination(destination_floor)
            else:
                moving_elevators = self.elevators
                if moving_elevators:
                    closest_elevator = min(moving_elevators, key=lambda e: abs(e.current_floor - floor))
                    closest_elevator.add_destination(floor)
                    closest_elevator.add_destination(destination_floor)

    def simulate_step(self):
        for elevator in self.elevators:
            elevator.move()

    def display_state(self):
        for elevator in self.elevators:
            print(elevator)
        print(f"Waiting People: {self.waiting_people}")
        print("-" * 20)

