        elif 1020 <= time_of_day <= 1140:  # 5:00 PM - 7:00 PM (Evening rush)
            probability = 0.05
        elif 720 <= time_of_day <= 900: # 12:00 PM - 3:00 PM (Lunch rush)
            probability = 0.02
        else:
            probability = 0.005

        for _ in range(num_people):
            if random.random() < probability:
                start_floor = random.randint(1, skyscraper.num_floors)
                destination_floor = random.randint(1, skyscraper.num_floors)
                while destination_floor == start_floor:
                    destination_floor = random.randint(1, skyscraper.num_floors)
                skyscraper.call_elevator(start_floor, destination_floor)

        skyscraper.simulate_step()
