    def run_simulation(self, duration, time_of_day):
        for _ in range(duration):
            self.generate_passenger(time_of_day)

            # Assign waiting passengers to elevators
            for passenger in list(self.waiting_passengers):
                self.assign_elevator(passenger)

            # Move elevators
            for elevator in self.elevators:
                if elevator.destination is not None:
                    arrived = elevator.move()
                    if arrived:
                        if elevator.current_floor in [p.current_floor for p in self.waiting_passengers if p.elevator_id == elevator.elevator_id]:
                            # Pick up passengers
                            passengers_to_pickup = [p for p in self.waiting_passengers if p.current_floor == elevator.current_floor and p.elevator_id == elevator.elevator_id]
                            for p in passengers_to_pickup:
                                elevator.add_passenger(p)
                                self.waiting_passengers.remove(p)
                                elevator.destination = p.destination_floor
                                print(f"Passenger {p.passenger_id} boarded Elevator {elevator.elevator_id}")
                        elif elevator.current_floor in [p.destination_floor for p in elevator.passengers]:
                            # Drop off passengers
                            passengers_to_dropoff = [p for p in elevator.passengers if p.destination_floor == elevator.current_floor]
                            for p in passengers_to_dropoff:
                                elevator.remove_passenger(p)
                                print(f"Passenger {p.passenger_id} exited Elevator {elevator.elevator_id}")
                            if not elevator.passengers:
                                elevator.destination = None

            # Print elevator statuses
            for elevator in self.elevators:
                print(elevator)

            time.sleep(0.2)

if __name__ == "__main__":
